import React, { useState } from "react";
import { ReactComponent as QuadradoAnatomico } from '../img/dentes/quadrado_anatomico.svg';

// Dentes superiores e inferiores na ordem FDI
const DENTES_SUP = [18,17,16,15,14,13,12,11,21,22,23,24,25,26,27,28];
const DENTES_INF = [48,47,46,45,44,43,42,41,31,32,33,34,35,36,37,38];

// Ícones dos tratamentos
const ICONES = [
  { key: "normal", icon: "Normal", label: "Normal" },
  { key: "implante", icon: <img src="/img/dentes/implante.svg" alt="Implante" style={{width: 22}} />, label: "Implante" },
  { key: "coroa", icon: <img src="/img/icones/coroa.svg" alt="Coroa" style={{width: 22}} />, label: "Coroa" },
  { key: "extracao", icon: <img src="/img/icones/extracao.svg" alt="Extração" style={{width: 22}} />, label: "Extração" },
];

// Busca imagem SVG do dente conforme tratamento, com fallback melhorado
function getSvgDente(num, tipo = "normal") {
  if (tipo && tipo !== "normal") {
    try {
      return require(`../img/dentes/${num}_${tipo}.svg`);
    } catch {
      try {
        return require(`../img/dentes/${tipo}.svg`);
      } catch {}
    }
  }
  try {
    return require(`../img/dentes/${num}.svg`);
  } catch {
    try {
      return require(`../img/dentes/generico.svg`);
    } catch {
      return "";
    }
  }
}

// Quadrado anatômico SVG do usuário, com clique dinâmico em cada face
function OdontoQuadrado({ faces, onClickFace }) {
  // Vamos pintar cada face via CSS dinamicamente (usando classes)
  // É preciso que o SVG tenha id="coroa", id="vestibular" etc
  // O onClick do SVG é global, mas podemos acessar o id do target
  return (
    <QuadradoAnatomico
      style={{ width: 36, height: 36, cursor: "pointer" }}
      onClick={e => {
        const face = e.target.id;
        if (face && ["coroa", "vestibular", "palatina", "mesial", "distal"].includes(face)) {
          onClickFace(face);
        }
      }}
    />
  );
}

// CSS dinâmico para pintar as faces (adicione no seu CSS global ou module)
const style = `
#coroa.selected, #vestibular.selected, #palatina.selected, #mesial.selected, #distal.selected {
  fill: #fbbf24 !important;
  stroke: #ea580c !important;
}
`;
// Insere estilo global uma vez
if (typeof document !== "undefined" && !document.getElementById("odontograma-faces-style")) {
  const styleTag = document.createElement("style");
  styleTag.id = "odontograma-faces-style";
  styleTag.innerHTML = style;
  document.head.appendChild(styleTag);
}

export default function OdontogramaDigital() {
  const [facesSelecionadas, setFacesSelecionadas] = useState({});
  const [dentesSelecionados, setDentesSelecionados] = useState({});
  const [tipoDente, setTipoDente] = useState({});

  // Troca cor da face clicada
  function toggleFace(dente, face) {
    setFacesSelecionadas(fs => ({
      ...fs,
      [dente]: {
        ...fs[dente],
        [face]: !fs[dente]?.[face]
      }
    }));
    setTimeout(() => {
      const svgList = document.querySelectorAll(`[data-dente="${dente}"] svg`);
      svgList.forEach(svg => {
        ["coroa", "vestibular", "palatina", "mesial", "distal"].forEach(f => {
          const elem = svg.getElementById(f);
          if (elem) {
            elem.classList.toggle("selected", !!facesSelecionadas?.[dente]?.[f]);
          }
        });
      });
    }, 10);
  }

  function toggleDenteCheckbox(dente) {
    setDentesSelecionados(ds => ({
      ...ds,
      [dente]: !ds[dente]
    }));
  }

  function handleIconeClick(dente, key) {
    setTipoDente(td => ({
      ...td,
      [dente]: td[dente] === key ? "normal" : key
    }));
  }

  function renderDentes(arr) {
    return arr.map(num => (
      <div key={num} className="flex flex-col items-center mx-1" style={{ minWidth: 54 }}>
        {/* Checkbox azul */}
        <input
          type="checkbox"
          checked={!!dentesSelecionados[num]}
          onChange={() => toggleDenteCheckbox(num)}
          className="accent-blue-600 mb-1"
          style={{width: 18, height: 18}}
        />
        {/* Imagem SVG do dente conforme tratamento */}
        <img
          src={getSvgDente(num, tipoDente[num] || "normal")}
          alt={`Dente ${num}`}
          style={{
            width: 38,
            height: 44,
            objectFit: "contain",
            marginBottom: -8,
            filter: tipoDente[num] === "extracao" ? "grayscale(1)" : undefined,
            opacity: tipoDente[num] === "extracao" ? 0.5 : 1,
            transition: "0.2s"
          }}
        />
        {/* Quadrado anatômico SVG do usuário */}
        <div data-dente={num}>
          <OdontoQuadrado
            faces={facesSelecionadas[num] || {}}
            onClickFace={face => toggleFace(num, face)}
          />
        </div>
        {/* Número FDI */}
        <span className="text-xs mt-1">{num}</span>
        {/* Ícones de tratamento - só se dente está selecionado */}
        {dentesSelecionados[num] && (
          <div className="flex gap-1 mt-1">
            {ICONES.map(ic => (
              <button
                key={ic.key}
                title={ic.label}
                onClick={() => handleIconeClick(num, ic.key)}
                className={`border rounded p-1 ${tipoDente[num] === ic.key ? "bg-blue-100" : "bg-white"} hover:bg-blue-50`}
                style={{ fontSize: 18, cursor: "pointer" }}
                type="button"
                tabIndex={0}
              >
                {ic.icon}
              </button>
            ))}
          </div>
        )}
      </div>
    ));
  }

  return (
    <div className="w-full max-w-6xl mx-auto p-4 bg-white rounded-xl shadow">
      <div className="text-lg font-bold text-center mb-4">Odontograma</div>
      <div className="flex justify-center mb-2">{renderDentes(DENTES_SUP)}</div>
      <div className="flex justify-center mt-2">{renderDentes(DENTES_INF)}</div>
      <div className="flex gap-6 mt-6 justify-center text-sm">
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-orange-400 border border-gray-400" /> Selecionado
        </div>
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-gray-300 border border-gray-400" /> Não selecionado
        </div>
      </div>
    </div>
  );
}
